#[async_trait]
impl<R: BulkOperationProjectionRepository> BulkOperationEventHandler for BulkOperationProjector<R> {

    async fn on_created(&self, event: BulkOperationCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = BulkOperationProjection::new(
            event.id,
            event.operation_type,
            event.status,
            event.created_by,
            event.total_records,
            event.processed_records,
            event.successful_records,
            event.failed_records,
            event.skipped_records,
            event.input_file_path,
            event.output_file_path,
            event.error_file_path,
            event.parameters,
            event.progress_percentage,
            event.started_at,
            event.completed_at,
            event.estimated_completion,
            event.error_message,
            event.retry_count,
            event.max_retries,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: BulkOperationUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.operation_type = event.operation_type;
            projection.status = event.status;
            projection.created_by = event.created_by;
            projection.total_records = event.total_records;
            projection.processed_records = event.processed_records;
            projection.successful_records = event.successful_records;
            projection.failed_records = event.failed_records;
            projection.skipped_records = event.skipped_records;
            projection.input_file_path = event.input_file_path;
            projection.output_file_path = event.output_file_path;
            projection.error_file_path = event.error_file_path;
            projection.parameters = event.parameters;
            projection.progress_percentage = event.progress_percentage;
            projection.started_at = event.started_at;
            projection.completed_at = event.completed_at;
            projection.estimated_completion = event.estimated_completion;
            projection.error_message = event.error_message;
            projection.retry_count = event.retry_count;
            projection.max_retries = event.max_retries;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: BulkOperationDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

